import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function aggregateReputation(walletAddress) {
  const [nfts, activity, balances] = await Promise.all([
    client.NftService.getNftsForAddress("eth-mainnet", walletAddress),
    client.AllChainsService.getAddressActivity(walletAddress),
    client.BalanceService.getTokenBalancesForWalletAddress("eth-mainnet", walletAddress),
  ]);
  const badgeCount = nfts.data?.items?.filter(n => n.type === "ERC-721")?.length ?? 0;
  const chainCount = activity.data?.items?.length ?? 0;
  return { walletAddress, reputationScore: badgeCount * 10 + chainCount * 15, badgeCount, chainCount };
}
